#include <stdio.h>
int main() {
    int N, K;
    scanf("%d %d", &N, &K);
    int A[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &A[i]);
    }
    long long dp[N];
    dp[0] = 1;
    long long ans = 1;
    for (int i = 1; i < N; i++) {
        dp[i] = 1;
        for (int j = 0; j < i; j++) {
            if (A[j] % A[i] == K) {
                dp[i] = dp[i] + dp[j];
            }
        }
        ans = ans + dp[i];
    }
    printf("%lld\n", ans);
    return 0;
}

